var e=[{id:`L1_1`,type:`dialog`,speaker:`REGINA_ESPR_NULL_NULL`,text:{KOREA:`이 사진은… 리플레이서 신디케이트가 만든 융합체인가요?`,JPN:`この写真は……リプレイサー・シンジケートが作った融合体ですか？`,ENG:`This photo... Is this not a hybrider made by the Replacer Syndicate?`,TWN:`這張照片是……克隆集團製造的融合體嗎？`},stage:{bg:`BLACK`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`REGINA_ESPR_NULL_NULL`,face:`UNIT_SURPRISE`},C:null,R:null}},sfx:`FX_CUTSCEN_NOISE_RUSTLE`},{id:`L2_1`,type:`dialog`,speaker:`BIO_NPC_ESPR2_NULL`,text:{KOREA:`생체병기로서는 그보다 한 단계 발전된 형태라오, 부학회장.`,JPN:`生体兵器としてはそれより一段階発展させた形態なのだ、副学会長。`,ENG:`Yes, but it has been upgraded as a more efficient bioweapon, Vice President.`,TWN:`據說是一種比融合體更先進的生化武器形態，副學會長。`},stage:{bg:`BLACK`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`REGINA_ESPR_NULL_NULL`,face:`UNIT_SURPRISE`},C:null,R:{char_id:`BIO_NPC_ESPR2_NULL`,face:`UNIT_IDLE`}}}},{id:`L3_1`,type:`dialog`,speaker:`BIO_NPC_ESPR2_NULL`,text:{KOREA:`그로니아로 도망친 리플레이서의 패잔병들을 상대로 실전 테스트도 시작했지.`,JPN:`グロニアに逃げたリプレイサーの敗残兵を相手に実戦テストも始まっている。`,ENG:`We have even conducted field tests on fallen Replacer soldiers who had fled to Gronia.`,TWN:`我們以逃到格羅尼亞的克隆集團殘兵為對象，進行了實戰測試。`},stage:{bg:`BLACK`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`REGINA_ESPR_NULL_NULL`,face:`UNIT_SURPRISE`},C:null,R:{char_id:`BIO_NPC_ESPR2_NULL`,face:`UNIT_IDLE`}}}},{id:`L4_1`,type:`dialog`,speaker:`REGINA_ESPR_NULL_NULL`,text:{KOREA:`전세계에 피해를 줬던 테러 조직입니다!`,JPN:`全世界に被害を与えたテロ組織ですわ！`,ENG:`They are terrorists who nearly destroyed the world!`,TWN:`那是給全世界造成損失的破壞分子組織！`},stage:{bg:`BLACK`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`REGINA_ESPR_NULL_NULL`,face:`UNIT_SERIOUS`},C:null,R:{char_id:`BIO_NPC_ESPR2_NULL`,face:`UNIT_IDLE`}}}},{id:`L5_1`,type:`dialog`,speaker:`REGINA_ESPR_NULL_NULL`,text:{KOREA:`리플레이서의 기술은 국제기구들이 연구를 금지했어요. 그런데 손을 댔다는 건가요?`,JPN:`リプレイサーの技術は国際機構が研究を禁じています。それなのに手を出したというのですか？`,ENG:`The international organization has banned research on Replacer technology. But you dare defy their authority?`,TWN:`國際機構已經禁止研究克隆集團的技術了。但你們還是插手了嗎？`},stage:{bg:`BLACK`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`REGINA_ESPR_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`BIO_NPC_ESPR2_NULL`,face:`UNIT_IDLE`}}}},{id:`L6_1`,type:`dialog`,speaker:`BIO_NPC_ESPR2_NULL`,text:{KOREA:`오해 마시오. 연구를 제안한 측은 북방 합의체니 말이오.`,JPN:`誤解しないでいただきたい。研究を提案したのは北方合意体の方だ。`,ENG:`Do not misunderstand. It was Northern Union who suggested the research.`,TWN:`請別誤會。提議研究的是北方合議會。`},stage:{bg:`BLACK`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`REGINA_ESPR_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`BIO_NPC_ESPR2_NULL`,face:`UNIT_IDLE`}}}},{id:`L7_1`,type:`dialog`,speaker:`REGINA_ESPR_NULL_NULL`,text:{KOREA:`뭐라고요……?`,JPN:`なんですって……？`,ENG:`What...?`,TWN:`你說什麼……？`},stage:{bg:`BLACK`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`REGINA_ESPR_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`BIO_NPC_ESPR2_NULL`,face:`UNIT_IDLE`}}}},{id:`L8_1`,type:`dialog`,speaker:`BIO_NPC_ESPR2_NULL`,text:{KOREA:`설마 무지한 자들이 자기 입 밖으로 내뱉은 말을 지킬 만큼 명예로운 줄 아셨소?`,JPN:`まさか無知な者たちが言い出したことを守るほど立派な連中だと思っておられたか？`,ENG:`Did you really think the ignoramuses would honor the words they made themselves?`,TWN:`難道你以為那些無知之人會懂得榮譽，遵守自己親口說出的承諾嗎？`},stage:{bg:`BLACK`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`REGINA_ESPR_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`BIO_NPC_ESPR2_NULL`,face:`UNIT_IDLE`}}}},{id:`L9_1`,type:`dialog`,speaker:`REGINA_ESPR_NULL_NULL`,text:{KOREA:`…….`,JPN:`……`,ENG:`...`,TWN:`……`},stage:{bg:`BLACK`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`REGINA_ESPR_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`BIO_NPC_ESPR2_NULL`,face:`UNIT_IDLE`}}}},{id:`L10_1`,type:`dialog`,speaker:`BIO_NPC_ESPR2_NULL`,text:{KOREA:`부학회장, 세상이 정말 무지한 자들의 망상대로 돌아가면 오죽 좋겠소만….`,JPN:`副学会長、世の中が本当に無知な者たちの妄想どおりに動くなら、それはいいだろうが……`,ENG:`As much as I would like to see the world revolve according to the delusions of these ignoramuses, Vice President...`,TWN:`副學會長，如果世界真的能像無知之人的妄想一樣運轉，當然很好……`},stage:{bg:`BLACK`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`REGINA_ESPR_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`BIO_NPC_ESPR2_NULL`,face:`UNIT_DESPAIR`}}}},{id:`L11_1`,type:`dialog`,speaker:`BIO_NPC_ESPR2_NULL`,text:{KOREA:`유감스럽게도 수단은 결과에 의해 정당화되는 법이오.`,JPN:`残念ながら手段は結果によって正当化されるものなのだ。`,ENG:`Historically, the ends have always justified the means.`,TWN:`但遺憾的是，各種低劣手段往往會在最終結果面前被正當化。`},stage:{bg:`BLACK`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`REGINA_ESPR_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`BIO_NPC_ESPR2_NULL`,face:`UNIT_IDLE`}}}}];export{e as default};